function MultiplyBonus(props) {
  props.className
  const paused = props.paused === undefined ? false : props.paused
  const onPause = props.onPause

  return jsxRuntime.jsxs(
    "div",
    {
      className: "animation-wrapper",
      children: [
        jsxRuntime.jsxs("svg", { ...SVG_PROPS, children: renderGaugePaths() }),
        jsxRuntime.jsx(MultiplyArrow, { paused, onPause }),
      ],
    },
  )
}

module.exports = { MultiplyBonus }

function renderGaugePaths() {
  return GAUGE_PATHS.map((pathProps) => jsxRuntime.jsx("path", pathProps))
}
